                            RoadSegmentId = nextSegmentId.Next(),
                            Geometry = RoadSegmentGeometry.Create(new MultiLineString([new LineString([new Coordinate(x - distanceIncrement, y), new Coordinate(x, y)])]).WithSrid(WellknownSrids.Lambert08)),
                            Status = RoadSegmentStatusV2.Gerealiseerd.ToString(),
                            GeometryDrawMethod = RoadSegmentGeometryDrawMethodV2.Ingemeten,
                            AccessRestriction = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, RoadSegmentAccessRestrictionV2.OpenbareWeg.ToString())]),
                            Category = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, RoadSegmentCategoryV2.NietGekend.ToString())]),
                            MaintenanceAuthorityId = new ExtractRoadSegmentDynamicAttribute<OrganizationId>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both,new OrganizationId(OrganizationOvoCode.DigitaalVlaanderen))]),
                            Morphology = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, RoadSegmentMorphologyV2.Parallelweg.ToString())]),
                            SurfaceType = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, RoadSegmentSurfaceTypeV2.Verhard.ToString())]),
                            StreetNameId = new ExtractRoadSegmentDynamicAttribute<StreetNameLocalId>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, StreetNameLocalId.NotApplicable)]),
                            EuropeanRoadNumbers = [],
                            NationalRoadNumbers = [],
                            IsV2 = true,
                            StartNodeId = null,
                            EndNodeId = null,
                            CarAccessBackward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, true)]),
                            CarAccessForward = new ExtractRoadSegmentDynamicAttribute<bool>([
                                (RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement / 2.0), RoadSegmentAttributeSide.Both, false),
                                (new RoadSegmentPositionV2(distanceIncrement / 2.0), new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, true)
                            ]),
                            BikeAccessBackward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, false)]),
                            BikeAccessForward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, false)]),
                            PedestrianAccess = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, false)]),
                            LastModified = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen),
                            Origin = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen)
                        };
                        if (transactionZoneGeometry.Disjoint(horizontalSegment.Geometry.Value))
                        {
                            continue;
                        }

                        _roadSegments.Add(horizontalSegment);
                        nextSegmentId = horizontalSegment.RoadSegmentId;

                        var nodeBelow = _roadNodes.SingleOrDefault(n => n.Geometry.Value.X == x && n.Geometry.Value.Y == y - distanceIncrement);
                        if (nodeBelow is not null)
                        {
                            var verticalSegment = new RoadSegmentExtractItem
                            {
                                RoadSegmentId = nextSegmentId.Next(),
                                Geometry = RoadSegmentGeometry.Create(new MultiLineString([new LineString([new Coordinate(x, y - distanceIncrement), new Coordinate(x, y)])]).WithSrid(WellknownSrids.Lambert08)),
                                Status = RoadSegmentStatusV2.Gerealiseerd.ToString(),
                                GeometryDrawMethod = RoadSegmentGeometryDrawMethodV2.Ingemeten,
                                AccessRestriction = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, RoadSegmentAccessRestrictionV2.OpenbareWeg.ToString())]),
                                Category = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, RoadSegmentCategoryV2.NietGekend.ToString())]),
                                MaintenanceAuthorityId = new ExtractRoadSegmentDynamicAttribute<OrganizationId>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, new OrganizationId(OrganizationOvoCode.DigitaalVlaanderen))]),
                                Morphology = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, RoadSegmentMorphologyV2.Parallelweg.ToString())]),
                                SurfaceType = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, RoadSegmentSurfaceTypeV2.Verhard.ToString())]),
                                StreetNameId = new ExtractRoadSegmentDynamicAttribute<StreetNameLocalId>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, StreetNameLocalId.NotApplicable)]),
                                EuropeanRoadNumbers = [],
                                NationalRoadNumbers = [NationalRoadNumber.Parse("N47")],
                                IsV2 = true,
                                StartNodeId = null,
                                EndNodeId = null,
                                CarAccessBackward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, true)]),
                                CarAccessForward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, true)]),
                                BikeAccessBackward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, false)]),
                                BikeAccessForward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, false)]),
                                PedestrianAccess = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(distanceIncrement), RoadSegmentAttributeSide.Both, false)]),
                                LastModified = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen),
                                Origin = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen)
                            };

                            if (transactionZoneGeometry.Disjoint(verticalSegment.Geometry.Value))
                            {
                                continue;
                            }

                            _roadSegments.Add(verticalSegment);
                            nextSegmentId = verticalSegment.RoadSegmentId;

                            if (firstJunction)
                            {
                                var segmentLength = 2;
                                var intersectingSegment = new RoadSegmentExtractItem
                                {
                                    RoadSegmentId = nextSegmentId.Next(),
                                    Geometry = RoadSegmentGeometry.Create(new MultiLineString([new LineString([new Coordinate(x - 1, y - (segmentLength / 2.0)), new Coordinate(x - 1, y + (segmentLength / 2.0))])]).WithSrid(WellknownSrids.Lambert08)),
                                    Status = RoadSegmentStatusV2.Gerealiseerd.ToString(),
                                    GeometryDrawMethod = RoadSegmentGeometryDrawMethodV2.Ingemeten,
                                    AccessRestriction = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, RoadSegmentAccessRestrictionV2.OpenbareWeg.ToString())]),
                                    Category = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, RoadSegmentCategoryV2.NietGekend.ToString())]),
                                    MaintenanceAuthorityId = new ExtractRoadSegmentDynamicAttribute<OrganizationId>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, new OrganizationId(OrganizationOvoCode.DigitaalVlaanderen))]),
                                    Morphology = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, RoadSegmentMorphologyV2.Parallelweg.ToString())]),
                                    SurfaceType = new ExtractRoadSegmentDynamicAttribute<string>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, RoadSegmentSurfaceTypeV2.Verhard.ToString())]),
                                    StreetNameId = new ExtractRoadSegmentDynamicAttribute<StreetNameLocalId>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, StreetNameLocalId.NotApplicable)]),
                                    EuropeanRoadNumbers = [],
                                    NationalRoadNumbers = [],
                                    IsV2 = true,
                                    StartNodeId = null,
                                    EndNodeId = null,
                                    CarAccessBackward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, true)]),
                                    CarAccessForward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, true)]),
                                    BikeAccessBackward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, false)]),
                                    BikeAccessForward = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, false)]),
                                    PedestrianAccess = new ExtractRoadSegmentDynamicAttribute<bool>([(RoadSegmentPositionV2.Zero, new RoadSegmentPositionV2(segmentLength), RoadSegmentAttributeSide.Both, false)]),
                                    LastModified = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen),
                                    Origin = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen)
                                };

                                if (transactionZoneGeometry.Disjoint(intersectingSegment.Geometry.Value))
                                {
                                    continue;
                                }

                                var nodeStart = new RoadNodeExtractItem
                                {
                                    RoadNodeId = nextNodeId.Next(),
                                    Geometry = RoadNodeGeometry.Create(intersectingSegment.Geometry.Value.GetSingleLineString().StartPoint),
                                    IsV2 = true,
                                    Type = RoadNodeTypeV2.Eindknoop,
                                    Grensknoop = false,
                                    LastModified = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen),
                                    Origin = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen)
                                };
                                var nodeEnd = new RoadNodeExtractItem
                                {
                                    RoadNodeId = nextNodeId.Next().Next(),
                                    Geometry = RoadNodeGeometry.Create(intersectingSegment.Geometry.Value.GetSingleLineString().EndPoint),
                                    IsV2 = true,
                                    Type = RoadNodeTypeV2.Eindknoop,
                                    Grensknoop = false,
                                    LastModified = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen),
                                    Origin = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen)
                                };

                                if (transactionZoneGeometry.Disjoint(intersectingSegment.Geometry.Value) ||
                                    transactionZoneGeometry.Disjoint(nodeStart.Geometry.Value) ||
                                    transactionZoneGeometry.Disjoint(nodeEnd.Geometry.Value))
                                {
                                    continue;
                                }

                                firstJunction = false;
                                _roadSegments.Add(intersectingSegment);
                                _roadNodes.Add(nodeStart);
                                _roadNodes.Add(nodeEnd);
                                nextSegmentId = intersectingSegment.RoadSegmentId;
                                nextNodeId = nodeEnd.RoadNodeId;

                                _gradeSeparatedJunctions.Add(new GradeSeparatedJunctionExtractItem
                                {
                                    IsV2 = true,
                                    GradeSeparatedJunctionId = nextJunctionId.Next(),
                                    Type = GradeSeparatedJunctionTypeV2.Brug,
                                    LowerRoadSegmentId = horizontalSegment.RoadSegmentId,
                                    UpperRoadSegmentId = intersectingSegment.RoadSegmentId,
                                    LastModified = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen),
                                    Origin = new EventTimestamp(Instant.FromDateTimeOffset(DateTimeOffset.Now), OrganizationId.DigitaalVlaanderen)
                                });
                                nextJunctionId = _gradeSeparatedJunctions.Last().GradeSeparatedJunctionId;
                            }
                        }
                    }
                    finally
                    {
                        x += distanceIncrement;
                    }
                }

                x = transactionZoneGeometry.EnvelopeInternal.MinX;
                y += distanceIncrement;
            }
        }

        public async Task<IReadOnlyList<RoadNodeExtractItem>> GetRoadNodes(IPolygonal contour, CancellationToken cancellationToken)
        {
            return _roadNodes;
        }

        public async Task<IReadOnlyList<RoadSegmentExtractItem>> GetRoadSegments(IPolygonal contour, CancellationToken cancellationToken)
        {
            return _roadSegments;
        }

        public async Task<IReadOnlyList<GradeSeparatedJunctionExtractItem>> GetGradeSeparatedJunctions(IPolygonal contour, CancellationToken cancellationToken)
        {
            return _gradeSeparatedJunctions;
        }

        public async Task<IReadOnlyList<OrganizationRecordV2>> GetOrganizations(CancellationToken cancellationToken)
        {
            return [];
        }
    }
}
